# Parse hex to bytes
bytes_list = bytes.fromhex(hex_data.replace(" ", ""))

# Convert to uint64 little-endian table
table1 = []
for i in range(256):
    val = struct.unpack("<Q", bytes_list[i*8:i*8+8])[0]
    table1.append(val)

# Build table2 (bit pattern transformation)
table2 = []
for i in range(256):
    val = 0
    for j in range(8):
        if (i & (1 << j)) != 0:
            val |= 0xFF << (j * 8)
    table2.append(val)

def hash_symbol(s):
    if len(s) == 0:
        return 0x8040201008040201
    
    rest_hash = hash_symbol(s[1:])
    char_byte = ord(s[0])
    char_lookup = table1[char_byte]
    
    result = 0
    for i in range(8):
        byte_idx = (char_lookup >> (i * 8)) & 0xFF
        lookup = table2[byte_idx]
        result ^= (lookup & rest_hash)
    
    return result

# Test with known symbols
symbols = [
    ("SNSLobbyRegistrationSuccess", 0xFEF8EFEC97A3B98),
    ("SNSLobbySessionStarting", 0x6d451003fb4b172e),  # This should be SAVE_LOADOUT based on gameserver.cpp
]

for sym, expected in symbols:
    computed = hash_symbol(sym)
    match = "✓" if computed == expected else "✗"
    print(f"{match} {sym}: 0x{computed:016x} (expected 0x{expected:016x})")
